package plugins.ldapservers.org.apache.directory.studio.ldapservers;

public class LdapServerAdapterExtensionsManager { public static final String ID_ATTR = "id" ; public static final String NAME_ATTR = "name" ; public static final String VERSION_ATTR = "version" ; public static final String VENDOR_ATTR = "vendor" ; public static final String CLASS_ATTR = "class" ; public static final String DESCRIPTION_ATTR = "description" ; public static final String ICON_ATTR = "icon" ; public static final String CONFIGURATION_PAGE_ATTR = "configurationPage" ; public static final String OPEN_CONFIGURATION_ACTION_ENABLED_ATTR = "openConfigurationActionEnabled" ; private static LdapServerAdapterExtensionsManager instance ; private List < LdapServerAdapterExtension > ldapServerAdapterExtensionsList ; private Map < String , LdapServerAdapterExtension > ldapServerAdapterExtensionsByIdMap ; private LdapServerAdapterExtensionsManager ( ) { } public void loadLdapServerAdapterExtensions ( ) { ldapServerAdapterExtensionsList = new ArrayList < LdapServerAdapterExtension > ( ) ; ldapServerAdapterExtensionsByIdMap = new HashMap < String , LdapServerAdapterExtension > ( ) ; IConfigurationElement [ ] members = Platform . getExtensionRegistry ( ) . getExtensionPoint ( LdapServersPluginConstants . LDAP_SERVER_ADAPTERS_EXTENSION_POINT ) . getConfigurationElements ( ) ; for ( IConfigurationElement member : members ) { LdapServerAdapterExtension ldapServerAdapterExtension = new LdapServerAdapterExtension ( ) ; String extendingPluginId = member . getDeclaringExtension ( ) . getNamespaceIdentifier ( ) ; ldapServerAdapterExtension . setExtensionPointConfiguration ( member ) ; ldapServerAdapterExtension . setId ( member . getAttribute ( ID_ATTR ) ) ; ldapServerAdapterExtension . setName ( member . getAttribute ( NAME_ATTR ) ) ; ldapServerAdapterExtension . setVersion ( member . getAttribute ( VERSION_ATTR ) ) ; ldapServerAdapterExtension . setVendor ( member . getAttribute ( VENDOR_ATTR ) ) ; ldapServerAdapterExtension . setClassName ( member . getAttribute ( CLASS_ATTR ) ) ; try { ldapServerAdapterExtension . setInstance ( ( LdapServerAdapter ) member . createExecutableExtension ( CLASS_ATTR ) ) ; } catch ( CoreException e ) { } ldapServerAdapterExtension . setDescription ( member . getAttribute ( DESCRIPTION_ATTR ) ) ; String iconPath = member . getAttribute ( ICON_ATTR ) ; if ( iconPath != null ) { ImageDescriptor icon = AbstractUIPlugin . imageDescriptorFromPlugin ( extendingPluginId , iconPath ) ; if ( icon == null ) { icon = ImageDescriptor . getMissingImageDescriptor ( ) ; } ldapServerAdapterExtension . setIcon ( icon ) ; } ldapServerAdapterExtension . setConfigurationPageClassName ( member . getAttribute ( CONFIGURATION_PAGE_ATTR ) ) ; String openConfigurationActionEnabled = member . getAttribute ( OPEN_CONFIGURATION_ACTION_ENABLED_ATTR ) ; if ( openConfigurationActionEnabled != null ) { ldapServerAdapterExtension . setOpenConfigurationActionEnabled ( Boolean . parseBoolean ( openConfigurationActionEnabled ) ) ; } else { ldapServerAdapterExtension . setOpenConfigurationActionEnabled ( true ) ; } ldapServerAdapterExtensionsList . add ( ldapServerAdapterExtension ) ; ldapServerAdapterExtensionsByIdMap . put ( ldapServerAdapterExtension . getId ( ) , ldapServerAdapterExtension ) ; } } public static LdapServerAdapterExtensionsManager getDefault ( ) { if ( instance == null ) { instance = new LdapServerAdapterExtensionsManager ( ) ; } return instance ; } public List < LdapServerAdapterExtension > getLdapServerAdapterExtensions ( ) { return ldapServerAdapterExtensionsList ; } public LdapServerAdapterExtension getLdapServerAdapterExtensionById ( String id ) { return ldapServerAdapterExtensionsByIdMap . get ( id ) ; } }